'.hms-kpi .t-Report-wrap,',
'.hms-kpi .t-Report-tableWrap {',
'    width: 100% !important;',
'    max-width: 100% !important;',
'    overflow: hidden !important;',
'}',
'',
'/* Convert the one-value report into a clean block */',
'.hms-kpi .t-Report-report {',
'    display: block !important;',
'    width: 100% !important;',
'    min-width: 0 !important;',
'    table-layout: fixed !important;',
'    border: 0 !important;',
'    background: transparent !important;',
'}',
'',
'.hms-kpi .t-Report-report thead {',
'    display: none !important;',
'}',
'',
'.hms-kpi .t-Report-report tbody,',
'.hms-kpi .t-Report-report tr {',
'    display: block !important;',
'    width: 100% !important;',
'}',
'',
'.hms-kpi .t-Report-report td {',
'    display: block !important;',
'    width: 100% !important;',
'    padding: 10px 20px 22px !important;',
'    border: 0 !important;',
'    background: transparent !important;',
'    color: #0f172a !important;',
'    font-size: 2.35rem !important;',
'    font-weight: 800 !important;',
'    line-height: 1 !important;',
'    white-space: normal !important;',
'}',
'',
'/* Hide report pagination and footer if generated */',
'.hms-kpi .t-Report-pagination,',
'.hms-kpi .t-Report-links,',
'.hms-kpi .t-Report-footer {',
'    display: none !important;',
'}',
'',
'/* Decorative shape */',
'.hms-kpi::before {',
'    content: "";',
'    position: absolute;',
'    right: -30px;',
'    bottom: -45px;',
'    width: 125px;',
'    height: 125px;',
'    border-radius: 50%;',
'    background: rgba(255, 255, 255, 0.52);',
'    pointer-events: none;',
'}',
'',
'.hms-kpi::after {',
'    content: "";',
'    position: absolute;',
'    right: 58px;',
'    bottom: -32px;',
'    width: 65px;',
'    height: 65px;',
'    border-radius: 50%;',
'    background: rgba(255, 255, 255, 0.28);',
'    pointer-events: none;',
'}',
'',
'/* =====================================================',
'   INDIVIDUAL KPI COLOURS',
