'        box-shadow 0.2s ease;',
'}',
'',
'.hms-chart:hover {',
'    transform: translateY(-3px);',
'    box-shadow: 0 13px 30px rgba(15, 23, 42, 0.13);',
'}',
'',
'/* Chart header */',
'.hms-chart .t-Region-header {',
'    min-height: 58px;',
'    padding: 14px 20px !important;',
'    border-bottom: 1px solid #e2e8f0 !important;',
'    background: linear-gradient(',
'        135deg,',
'        #ffffff 0%,',
'        #f8fafc 100%',
'    ) !important;',
'}',
'',
'/* Chart title */',
'.hms-chart .t-Region-title {',
'    color: #172033 !important;',
'    font-size: 1.05rem !important;',
'    font-weight: 750 !important;',
'}',
'',
'/* Chart body spacing */',
'.hms-chart .t-Region-body {',
'    padding: 18px 18px 12px !important;',
'    background: #ffffff !important;',
'}',
'',
'/* Prevent accidental chart-region scrollbars */',
'.hms-chart .t-Region-bodyWrap,',
'.hms-chart .t-Region-body {',
'    overflow: hidden !important;',
'}',
'',
'/* Small colour line at top */',
'.hms-chart::before {',
'    content: "";',
'    position: absolute;',
'    z-index: 3;',
'    top: 0;',
'    left: 0;',
'    width: 100%;',
'    height: 5px;',
'}',
'',
'/* Individual chart accents */',
'#chart-appointments::before {',
'    background: linear-gradient(',
