,p_validation=>wwv_flow_string.join(wwv_flow_t_varchar2(
'BEGIN',
'    IF :P25_APPOINTMENT_DATE IS NULL THEN',
'        RETURN TRUE;',
'    END IF;',
'',
'    RETURN TO_DATE(',
'               :P25_APPOINTMENT_DATE,',
'               ''DD-MON-YYYY'',',
'               ''NLS_DATE_LANGUAGE=ENGLISH''',
'           ) >= TRUNC(SYSDATE);',
'EXCEPTION',
'    WHEN OTHERS THEN',
'        RETURN FALSE;',
'END;'))
,p_validation2=>'PLSQL'
,p_validation_type=>'FUNC_BODY_RETURNING_BOOLEAN'
